// --- Objection Normalization ---
const knownCategories = [
  'Kein Budget', 'Keine Zeit', 'Nutze bereits Zapier', 'Muss Team fragen',
  'Zu komplex', 'Kein konkreter Bedarf', 'Datenschutzbedenken',
  'Vertrag mit Wettbewerber', 'Brauche mehr Infos', 'Zu teuer',
  'IT muss zustimmen', 'Nicht der Entscheider', 'Kein Bedarf aktuell'
];
let allKnown = [...knownCategories];
try {
  const existCats = $('Build OpenRouter Request').first().json.existingCategoryNames;
  if (Array.isArray(existCats) && existCats.length > 0) {
    existCats.forEach(c => {
      if (!allKnown.some(k => k.toLowerCase() === c.toLowerCase())) allKnown.push(c);
    });
  }
} catch(e) {}

const synonymMap = {
  'budget': 'Kein Budget', 'teuer': 'Kein Budget', 'kosten': 'Kein Budget', 'preis': 'Kein Budget', 'geld': 'Kein Budget',
  'zeit': 'Keine Zeit', 'zapier': 'Nutze bereits Zapier', 'make.com': 'Nutze bereits Zapier', 'integromat': 'Nutze bereits Zapier',
  'team fragen': 'Muss Team fragen', 'chef': 'Muss Team fragen', 'vorstand': 'Muss Team fragen', 'entscheider': 'Muss Team fragen', 'genehmig': 'Muss Team fragen',
  'komplex': 'Zu komplex', 'kompliziert': 'Zu komplex', 'aufwaendig': 'Zu komplex',
  'bedarf': 'Kein konkreter Bedarf', 'datenschutz': 'Datenschutzbedenken', 'dsgvo': 'Datenschutzbedenken',
  'wettbewerber': 'Vertrag mit Wettbewerber', 'konkurrent': 'Vertrag mit Wettbewerber', 'vertrag': 'Vertrag mit Wettbewerber'
};

function normalizeObjToCanonical(obj) {
  const trimmed = String(obj).trim();
  if (!trimmed) return null;
  const lower = trimmed.toLowerCase();
  const exactMatch = allKnown.find(k => k.toLowerCase() === lower);
  if (exactMatch) return exactMatch;
  for (const [keyword, canonical] of Object.entries(synonymMap)) {
    if (lower.includes(keyword)) return canonical;
  }
  const cleaned = trimmed.substring(0, 50).replace(/[.!?]+$/g, '').trim();
  return cleaned.charAt(0).toUpperCase() + cleaned.slice(1);
}

const rawObjections = Array.isArray(parsed.objections_raised) ? parsed.objections_raised : [];
const normalizedObjections = [];
const seenNorm = new Set();
for (const obj of rawObjections) {
  const norm = normalizeObjToCanonical(obj);
  if (norm && !seenNorm.has(norm.toLowerCase())) { seenNorm.add(norm.toLowerCase()); normalizedObjections.push(norm); }
}

// --- Drop-off phase validation ---
const validPhases = ['OPENING', 'DISCOVERY', 'QUALIFICATION', 'DEMO_OFFER', 'CLOSING'];
const rawDropOff = parsed.drop_off_point;
let normalizedDropOff = null;
if (rawDropOff) {
  const upperDropOff = String(rawDropOff).toUpperCase().trim();
  if (validPhases.includes(upperDropOff)) normalizedDropOff = upperDropOff;
  else {
    const aliases = { 'PAIN_VALIDATION': 'DISCOVERY', 'SOLUTION': 'DEMO_OFFER', 'GREETING': 'OPENING', 'INTRO': 'OPENING' };
    normalizedDropOff = aliases[upperDropOff] || 'DISCOVERY';
  }
}

// --- Parse scoring evidence ---
const validDimensions = ['company_size', 'tech_stack', 'pain_point', 'timeline', 'engagement', 'sentiment', 'objection', 'drop_off', 'general'];
const validSpeakers = ['agent', 'caller'];
const validSentiments = ['positiv', 'neutral', 'negativ'];

let scoringEvidence = [];
if (Array.isArray(parsed.scoring_evidence)) {
  scoringEvidence = parsed.scoring_evidence
    .filter(e => e && typeof e === 'object' && typeof e.quote_text === 'string' && e.quote_text.trim().length > 0)
    .map(e => ({
      dimension: validDimensions.includes(e.dimension) ? e.dimension : 'general',
      quote_text: String(e.quote_text).substring(0, 1000).trim(),
      speaker: validSpeakers.includes(e.speaker) ? e.speaker : 'caller',
      reasoning: sanitizeStr(e.reasoning, 500) || '',
      score_value: e.score_value != null ? clamp(e.score_value, 1, 3) : null,
      sentiment: validSentiments.includes(e.sentiment) ? e.sentiment : 'neutral'
    }));
}

const result = {
  callId: extractData.callId, phone: extractData.phone,
  callDurationSeconds: extractData.callDurationSeconds, callStartedAt: extractData.callStartedAt,
  transcript: extractData.transcript, endedReason: extractData.endedReason,
  recordingUrl: extractData.recordingUrl, callDirection: extractData.callDirection,
  campaignId: extractData.campaignId, leadId: extractData.leadId, attemptNumber: extractData.attemptNumber,
  score_company_size: clamp(parsed.score_company_size, 1, 3),
  score_tech_stack: clamp(parsed.score_tech_stack, 1, 3),
  score_pain_point: clamp(parsed.score_pain_point, 1, 3),
  score_timeline: clamp(parsed.score_timeline, 1, 3),
  score_engagement: clamp(parsed.score_engagement, 1, 3),
  conversation_summary: String(parsed.conversation_summary || '').substring(0, 1000),
  sentiment, sentiment_score: sentimentScore,
  sentiment_reason: sanitizeStr(parsed.sentiment_reason, 500),
  objections_raised: normalizedObjections,
  drop_off_point: normalizedDropOff,
  is_decision_maker: Boolean(parsed.is_decision_maker),
  status: validStatuses.includes(parsed.status) ? parsed.status : 'contacted',
  next_steps: Array.isArray(parsed.next_steps) ? parsed.next_steps : [],
  caller_name: sanitizeStr(parsed.caller_name, 200),
  company: sanitizeStr(parsed.company, 200),
  company_size: sanitizeStr(parsed.company_size, 200),
  current_stack: sanitizeStr(parsed.current_stack, 500),
  pain_point: sanitizeStr(parsed.pain_point, 500),
  timeline: sanitizeStr(parsed.timeline, 200),
  dnc_requested: Boolean(parsed.dnc_requested),
  disposition_code: validDispositions.includes(parsed.disposition_code) ? parsed.disposition_code : 'connected'
};

// Ensure at least one evidence per main dimension
const mainDimensions = ['company_size', 'tech_stack', 'pain_point', 'timeline'];
const dimensionScoreMap = { company_size: result.score_company_size, tech_stack: result.score_tech_stack, pain_point: result.score_pain_point, timeline: result.score_timeline };
for (const dim of mainDimensions) {
  if (!scoringEvidence.some(e => e.dimension === dim)) {
    scoringEvidence.push({ dimension: dim, quote_text: 'Keine relevante Aussage im Gespraech', speaker: 'caller', reasoning: 'Dimension wurde im Gespraech nicht angesprochen, Standardwert vergeben', score_value: dimensionScoreMap[dim], sentiment: 'neutral' });
  }
}

result.scoringEvidence = scoringEvidence;
return [{ json: result }];

const parsed = $input.first().json;
const extractData = $('Extract Call Data').first().json;
let existingNames = [];
try {
  existingNames = $('Build OpenRouter Request').first().json.existingCategoryNames || [];
} catch(e) {}

const normalize = (s) => s.trim().replace(/\s+/g, ' ');
const objections = Array.isArray(parsed.objections_raised) ? parsed.objections_raised : [];

// Build lookup with both exact and keyword-based matching
const existingLower = existingNames.map(n => normalize(n).toLowerCase());

// Extract keywords from existing names for fuzzy matching
const stopwords = ['kein', 'keine', 'keinen', 'keinem', 'zu', 'mit', 'und', 'oder', 'nicht', 'muss', 'bereits', 'nutze', 'der', 'die', 'das', 'ein', 'eine'];
function extractKeywords(name) {
  return name.toLowerCase()
    .replace(/[^a-z\u00e4\u00f6\u00fc\u00df\s]/g, '')
    .split(/\s+/)
    .filter(w => w.length > 2 && !stopwords.includes(w));
}

const existingKeywordSets = existingNames.map(n => ({
  name: n,
  keywords: extractKeywords(n)
}));

function isExistingCategory(objection) {
  const lower = normalize(objection).toLowerCase();
  // Exact match
  if (existingLower.includes(lower)) return true;
  // Keyword overlap: if >=50% of new objection's keywords match an existing category
  const objKeywords = extractKeywords(objection);
  if (objKeywords.length === 0) return false;
  for (const existing of existingKeywordSets) {
    if (existing.keywords.length === 0) continue;
    const overlap = objKeywords.filter(k =>
      existing.keywords.some(ek => ek.includes(k) || k.includes(ek))
    ).length;
    if (overlap / Math.max(objKeywords.length, 1) >= 0.5) return true;
  }
  return false;
}

const newCats = objections.filter(obj => !isExistingCategory(obj));
const seen = new Set();
const uniqueNew = [];
for (const cat of newCats) {
  const key = normalize(cat).toLowerCase();
  if (!seen.has(key)) { seen.add(key); uniqueNew.push(normalize(cat)); }
}
const upsertBody = uniqueNew.map(name => ({ name, description: null, counter_argument: null, is_active: true, occurrence_count: 0 }));
return [{ json: {
  ...parsed,
  callId: parsed.callId || extractData.callId,
  phone: parsed.phone || extractData.phone,
  callDurationSeconds: parsed.callDurationSeconds || extractData.callDurationSeconds,
  callStartedAt: parsed.callStartedAt || extractData.callStartedAt,
  transcript: parsed.transcript || extractData.transcript,
  endedReason: parsed.endedReason || extractData.endedReason,
  recordingUrl: parsed.recordingUrl || extractData.recordingUrl,
  callDirection: parsed.callDirection || extractData.callDirection,
  campaignId: parsed.campaignId || extractData.campaignId,
  leadId: parsed.leadId || extractData.leadId,
  attemptNumber: parsed.attemptNumber || extractData.attemptNumber,
  upsertBody: JSON.stringify(upsertBody),
  hasNewCategories: uniqueNew.length > 0
} }];

// Disposition Inference: map Vapi endedReason + GPT analysis to final disposition_code
let d;
try {
  d = $('Detect New Categories').first().json;
} catch(e) {
  d = $input.first().json;
}

const endedReason = d.endedReason || 'unknown';
const gptDisposition = d.disposition_code || 'connected';
const dncRequested = Boolean(d.dnc_requested);
const scoreEngagement = d.score_engagement || 1;
const appointmentBooked = d.status === 'appointment_booked' || d.status === 'converted';

let finalDisposition = 'connected';
let finalStatus = d.status || 'contacted';
let finalOutboundState = null;

const nonConnectedReasons = {
  'no-answer': 'no_answer',
  'voicemail': 'voicemail',
  'machine-detected': 'voicemail',
  'busy': 'busy'
};

const technicalErrors = ['system-error', 'pipeline-error-openai', 'pipeline-error-custom-llm', 'pipeline-error-deepgram', 'pipeline-error-eleven-labs', 'pipeline-error-vapi'];

if (nonConnectedReasons[endedReason]) {
  finalDisposition = nonConnectedReasons[endedReason];
  finalStatus = d.status === 'new' ? 'new' : 'contacted';
  finalOutboundState = 'not_reached';
} else if (technicalErrors.includes(endedReason)) {
  finalDisposition = 'technical_error';
  finalStatus = d.status || 'contacted';
} else {
  if (appointmentBooked) {
    finalDisposition = 'connected';
    finalStatus = 'appointment_booked';
  } else if (dncRequested) {
    finalDisposition = 'dnc_request';
    finalStatus = 'lost';
  } else if (gptDisposition === 'not_interested' || scoreEngagement <= 1) {
    finalDisposition = 'not_interested';
    finalStatus = 'lost';
  } else if (gptDisposition === 'callback') {
    finalDisposition = 'callback';
    finalOutboundState = 'callback_scheduled';
  } else {
    finalDisposition = gptDisposition || 'connected';
  }
}

return [{ json: {
  ...d,
  disposition_code: finalDisposition,
  status: finalStatus,
  outbound_state: finalOutboundState,
  dnc_requested: dncRequested
} }];

// Smart Cadence: calculate next_call_scheduled_at and follow_up_reason
const d = $input.first().json;
const disposition = d.disposition_code;
const now = new Date();
const currentHour = now.getHours();
const isMorning = currentHour < 13;

function addWorkdays(date, days) {
  const result = new Date(date);
  let added = 0;
  while (added < days) {
    result.setDate(result.getDate() + 1);
    const dow = result.getDay();
    if (dow !== 0 && dow !== 6) added++;
  }
  return result;
}

function setTime(date, hours, minutes) {
  const result = new Date(date);
  result.setHours(hours, minutes || 0, 0, 0);
  return result;
}

let nextCallScheduledAt = null;
let followUpReason = null;

const terminalDispositions = ['not_interested', 'dnc_request', 'wrong_number'];

if (terminalDispositions.includes(disposition)) {
  nextCallScheduledAt = null;
  followUpReason = null;
} else if (disposition === 'no_answer') {
  if (isMorning) {
    const next = addWorkdays(now, 1);
    const hour = 14 + Math.floor(Math.random() * 2);
    nextCallScheduledAt = setTime(next, hour, Math.floor(Math.random() * 60)).toISOString();
    followUpReason = 'Vormittags nicht erreicht \u2014 Nachmittag versuchen';
  } else {
    const next = addWorkdays(now, 1);
    const hour = 9 + Math.floor(Math.random() * 2);
    nextCallScheduledAt = setTime(next, hour, Math.floor(Math.random() * 60)).toISOString();
    followUpReason = 'Nachmittags nicht erreicht \u2014 Vormittag versuchen';
  }
} else if (disposition === 'voicemail') {
  const next = addWorkdays(now, 2);
  const hour = isMorning ? (14 + Math.floor(Math.random() * 3)) : (9 + Math.floor(Math.random() * 2));
  nextCallScheduledAt = setTime(next, hour, Math.floor(Math.random() * 60)).toISOString();
  followUpReason = 'Mailbox erreicht \u2014 andere Tageszeit versuchen';
} else if (disposition === 'busy') {
  const next = new Date(now.getTime() + 2 * 60 * 60 * 1000);
  nextCallScheduledAt = next.toISOString();
  followUpReason = 'Besetzt \u2014 in 2 Stunden erneut versuchen';
} else if (disposition === 'gatekeeper') {
  const next = addWorkdays(now, 1);
  nextCallScheduledAt = setTime(next, 8, 30).toISOString();
  followUpReason = 'Gatekeeper \u2014 fr\u00fch morgens direkt versuchen';
} else if (disposition === 'callback') {
  if (d.callback_datetime) {
    nextCallScheduledAt = d.callback_datetime;
  } else {
    const next = addWorkdays(now, 1);
    nextCallScheduledAt = setTime(next, 10, 0).toISOString();
  }
  followUpReason = 'R\u00fcckruf vereinbart';
} else if (disposition === 'connected') {
  const next = addWorkdays(now, 3);
  nextCallScheduledAt = setTime(next, 10, 0).toISOString();
  followUpReason = 'Gespr\u00e4ch gef\u00fchrt \u2014 Follow-up in 3 Tagen';
} else if (disposition === 'technical_error') {
  const next = new Date(now.getTime() + 30 * 60 * 1000);
  nextCallScheduledAt = next.toISOString();
  followUpReason = 'Technischer Fehler \u2014 baldiger Retry';
}

return [{ json: {
  ...d,
  next_call_scheduled_at: nextCallScheduledAt,
  follow_up_reason: followUpReason
} }];

// DNC Check: extract lead_id from RETURNING and prepare data for DNC + call_attempt
const payload = $('Build Supabase Payload').first().json;
const upsertResult = $input.first().json;

const row = Array.isArray(upsertResult) ? upsertResult[0] : upsertResult;
const leadId = (row && row.id) ? row.id : payload.leadId || null;
const callId = payload.callId;
const phone = payload.phone;
const dncRequested = Boolean(payload.dnc_requested);

return [{ json: {
  leadId,
  callId,
  phone,
  dncRequested,
  disposition_code: payload.disposition_code,
  recording_url: payload.recording_url,
  callDirection: payload.callDirection,
  campaignId: payload.campaignId,
  attemptNumber: payload.attemptNumber,
  callDurationSeconds: payload.callDurationSeconds,
  endedReason: payload.endedReason,
  objections_raised: payload.objections_raised
} }];

