const upsertResult = $input.first().json;
const payload = $('Build Supabase Payload').first().json;

const row = Array.isArray(upsertResult) ? upsertResult[0] : upsertResult;
const leadId = (row && row.id) ? row.id : null;

if (!leadId) return [{ json: { hasQuotes: false, quotesBody: '[]', leadId: null } }];

const scoringEvidence = payload.scoringEvidence || [];
if (scoringEvidence.length === 0) return [{ json: { hasQuotes: false, quotesBody: '[]', leadId } }];

const quotes = scoringEvidence.map(e => ({
  lead_id: leadId,
  quote_text: String(e.quote_text || '').substring(0, 1000),
  speaker: e.speaker || 'caller',
  topic: e.dimension || 'general',
  sentiment: e.sentiment || 'neutral',
  context: e.reasoning || null,
  scoring_dimension: e.dimension || 'general',
  score_value: e.score_value
}));

return [{ json: { hasQuotes: true, quotesBody: JSON.stringify(quotes), leadId } }];
